import './App.css';
import React, {useEffect, useState} from "react";
import Axios from "axios";
import styles from "./styles.module.css";
import 'react-edit-text/dist/index.css';

function App() {
    const [listOfBooks, setListOfBooks] = useState([]);
    const [title, setTitle] = useState("");
    const [author, setAuthor] = useState("");
    const [year, setYear] = useState(0);

    async function fetchData() {
        const response = await Axios.get(process.env.REACT_APP_HOST_LINK + "/getBooks");
        setListOfBooks(response.data)
    }

    useEffect(() => {
        fetchData();
    }, []);

    const createBook = () => {
        Axios.post(process.env.REACT_APP_HOST_LINK + "/createBook", {
            title, author, year,
        }).then(() => {
            fetchData();
        });
    };


    const deleteBook = (id) => {
        Axios.delete(`http://localhost:3000/deleteBook/${id}`)
            .then((id) => {
                console.log(id);
                fetchData();
            });
    };

    const clearBooks = () => {
        Axios.delete("http://localhost:3000/clearBooks/")
            .then((response) => {
                console.log(response);
                fetchData();
            });
    };

    const updateBook = (id, newBookAuthor, newBookTitle, newBookYear) => {
        Axios.put("http://localhost:3000/updateBook/", {
            id: id,
            author: newBookAuthor,
            title:  newBookTitle,
            year: newBookYear
        })
            .then((id) => {
                console.log(id, newBookAuthor, newBookTitle, newBookYear);
                console.log(id);
                fetchData();
            });
    };

    return (<div className="App">
        <div className="booksDisplay">
            {listOfBooks.map((book) => {
                return (<div className={styles.booksParent}>
                    <h1 className={styles.title}>{book.title}</h1>
                    <h1 className={styles.author}>{book.author}</h1>
                    <h1 className={styles.year}>{book.year}</h1>
                    <button onClick={() => {
                        const newBookTitle = prompt('Please enter the new title');
                        const newBookAuthor = prompt('Please enter the new author');
                        const newBookYear = prompt('Please enter the new year')
                        if ((newBookTitle && newBookAuthor && newBookYear)) {
                            updateBook(book._id)
                        } else {
                            window.alert("yo chill fill all the boxes in");
                        }
                    }}> Update
                    </button>
                    <button onClick={() => {
                        if (window.confirm('Confirm deletion?')) {
                                deleteBook(book._id)
                        }
                    }}> Delete
                    </button>
                </div>)
            })}
        </div>
        <div>
            <input
                type="text"
                placeholder="Title"
                onChange={(event) => {
                    setTitle(event.target.value);
                }}
            />
            <input
                type="text"
                placeholder="Author"
                onChange={(event) => {
                    setAuthor(event.target.value);
                }}
            />
            <input
                type="number"
                placeholder="Year"
                onChange={(event) => {
                    setYear(event.target.value);
                }}
            />
            <button onClick={createBook}> Create Book</button>
            <button onClick={() => {
                if (window.confirm('Confirm clear?')) {
                    clearBooks();
                }
            }}> Clear Books
            </button>
        </div>
    </div>);
}

export default App;
